class Queue:
   def __init__(self):
       self.front = 0
       self.rear = -1
       self.size = 0
       self.elements = [None]*100

   def enqueue(self, x):
       self.elements[self.rear + 1] = x
       self.rear += 1
       self.size += 1

   def dequeue(self):
       if self.size > 0:
           value = self.elements[self.front]
           self.front += 1
           self.size -= 1
           return value
       else:
           return None


