class Queue { 
   int front; 
   int rear; 
   int size; 
   int elements[100]; 

   Queue() { 
       front = 0; 
       rear = -1; 
       size = 0; 
   }

   void enqueue(int x) { 
       elements[++rear] = x; 
       size++; 
   }

   int dequeue() { 
       if (size > 0) { 
           int value = elements[front++]; 
           size--; 
           return value; 
       } else { 
           return 0; 
       }
   }

   bool empty() { 
       return size == 0; 
   }

};

int main() {
   Queue q;
   int lines;
   scanf("%d", &lines);
   for (int i = 0; i < lines; i++) {
       int elements;
       scanf("%d", &elements);
       q.enqueue(elements);
   }
   printf("%d\n", q.dequeue());
   return 0;
}
